write(f"{root}/quasi_domain_registry.py", """
from dataclasses import dataclass, field
from typing import Dict, Any, Optional, Callable
import time

DOMAINS = [
    "memory",
    "voice_audio",
    "vision_foresight",
    "tactile_spatial",
    "cognitive_language",
    "multimodality",
    "temporal_presence",
    "meta_sfo",
]

@dataclass
class QuasiDomain:
    name: str
    created_at: float = field(default_factory=time.time)
    energy_level: float = 0.0
    energy_requested: float = 0.0
    energy_cap: float = 1.0
    fragment_state: Dict[str, Any] = field(default_factory=dict)
    pulse: Optional[Callable[[], Dict[str, Any]]] = None
    apply_correction: Optional[Callable[[float, str], None]] = None

class QuasiDomainRegistry:
    def __init__(self):
        self.domains: Dict[str, QuasiDomain] = {d: QuasiDomain(d) for d in DOMAINS}
        self.metashard_sync: Optional[Callable[[Dict[str, Any]], None]] = None

    def get(self, name: str) -> QuasiDomain:
        if name not in self.domains:
            self.domains[name] = QuasiDomain(name)
        return self.domains[name]

    def set_energy_observation(self, name: str, requested: float, level: float, cap: float = 1.0):
        q = self.get(name)
        q.energy_requested = max(0.0, float(requested))
        q.energy_level = max(0.0, float(level))
        q.energy_cap = max(0.01, float(cap))

    def set_fragment_state(self, name: str, state: Dict[str, Any]):
        self.get(name).fragment_state = dict(state or {})

    def wire_pulse(self, name: str, fn: Callable[[], Dict[str, Any]]):
        self.get(name).pulse = fn

    def wire_correction(self, name: str, fn: Callable[[float, str], None]):
        self.get(name).apply_correction = fn

    def broadcast_tick(self) -> Dict[str, Any]:
        snapshot = {}
        for name, q in self.domains.items():
            local = dict(
                energy=dict(requested=q.energy_requested, level=q.energy_level, cap=q.energy_cap),
                fragment=q.fragment_state,
            )
            if q.pulse:
                try:
                    local["pulse"] = q.pulse() or {}
                except Exception as e:
                    local["pulse_error"] = str(e)
            snapshot[name] = local
        if self.metashard_sync:
            try:
                self.metashard_sync(snapshot)
            except Exception:
                pass
        return snapshot

REGISTRY = QuasiDomainRegistry()
""")

