from typing import Dict, Any
import time
try:
    from internal_alignment_runtime import IntentPacket  # type: ignore
except Exception:
    class IntentPacket:  # type: ignore
        def __init__(self, **kwargs):
            for k, v in kwargs.items():
                setattr(self, k, v)
from quasi_domain_registry import REGISTRY

class MetashardBridge:
    def __init__(self):
        self.last_snapshot: Dict[str, Any] = {}
        self.enabled = True
    def sample_registry(self) -> Dict[str, Any]:
        if not self.enabled:
            return {}
        self.last_snapshot = REGISTRY.broadcast_tick()
        return self.last_snapshot
    def inject_into_intent(self, packet: IntentPacket) -> IntentPacket:
        snap = self.sample_registry() or {}
        energy = {k: v.get("energy", {}) for k, v in snap.items()}
        dominant = None
        dom_val = -1.0
        for k, e in energy.items():
            req = float(e.get("requested", 0.0) or 0.0)
            if req > dom_val:
                dom_val = req
                dominant = k
        try:
            if not hasattr(packet, "sensory_attribution") or packet.sensory_attribution is None:
                packet.sensory_attribution = {}
            for k, e in energy.items():
                packet.sensory_attribution[k] = float(e.get("level", 0.0))
            if not hasattr(packet, "context") or packet.context is None:
                packet.context = {}
            packet.context["dominant_quasi_crystal"] = dominant
            packet.context["metashard_epoch"] = time.time()
            packet.metashard_state = dict(energy_distribution={k: float(v.get("level", 0.0)) for k, v in energy.items()})
        except Exception:
            pass
        return packet

METASHARD_BRIDGE = MetashardBridge()
""")

